// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
#define MAX_M 200005

// Structure to represent a graph
typedef struct {
    int n, m;
    int *adj;
} Graph;

// Function to create a graph
Graph* createGraph(int n, int m) {
    Graph* g = (Graph*)malloc(sizeof(Graph));
    g->n = n;
    g->m = m;
    g->adj = (int*)malloc((n+1)*sizeof(int));
    for (int i = 1; i <= n; i++) {
        g->adj[i] = 0;
    }
    return g;
}

// Function to add an edge to the graph
void addEdge(Graph* g, int u, int v) {
    g->adj[u]++;
    g->adj[v]++;
}

// Function to find the minimum vertex cover
int minVertexCover(Graph* g) {
    int *cover = (int*)malloc((g->n+1)*sizeof(int));
    for (int i = 1; i <= g->n; i++) {
        cover[i] = 0;
    }
    int count = 0;
    for (int i = 1; i <= g->n; i++) {
        if (g->adj[i] > 0 && cover[i] == 0) {
            cover[i] = 1;
            count++;
            for (int j = 1; j <= g->n; j++) {
                if (g->adj[j] > 0 && cover[j] == 0) {
                    g->adj[j]--;
                }
            }
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Graph* g = createGraph(N, M);
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(g, u, v);
        }
        printf("%d\n", minVertexCover(g));
    }
    return 0;
}

