#include <iostream>
#include <vector>
using namespace std;

// Structure to represent a graph
struct Graph {
    int n, m;
    vector<vector<int>> adj;
};

// Function to create a graph
Graph createGraph(int n, int m) {
    Graph g;
    g.n = n;
    g.m = m;
    g.adj.resize(n+1);
    return g;
}

// Function to add an edge to the graph
void addEdge(Graph& g, int u, int v) {
    g.adj[u].push_back(v);
    g.adj[v].push_back(u);
}

// Function to find the minimum vertex cover
int minVertexCover(Graph& g) {
    vector<int> cover(g.n+1, 0);
    int count = 0;
    for (int i = 1; i <= g.n; i++) {
        if (g.adj[i].size() > 0 && cover[i] == 0) {
            cover[i] = 1;
            count++;
            for (int j = 1; j <= g.n; j++) {
                if (g.adj[j].size() > 0 && cover[j] == 0) {
                    g.adj[j].pop_back();
                }
            }
        }
    }
    return count;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, M;
        cin >> N >> M;
        Graph g = createGraph(N, M);
        for (int i = 0; i < M; i++) {
            int u, v;
            cin >> u >> v;
            addEdge(g, u, v);
        }
        cout << minVertexCover(g) << endl;
    }
    return 0;
}

